schema:
{
    "description": "An entity representing a person or identity.",
    "properties": {
        "_id": {
            "type": "string"
        },
        "email": {
            "_format": "email",
            "title": "Email Address",
            "type": "string"
        },
        "identityProviders": {
            "items": {
                "properties": {
                    "id": {
                        "type": "string"
                    },
                    "name": {
                        "type": "string"
                    }
                },
                "type": "object"
            },
            "type": "array"
        },
        "name": {
            "title": "Full Name",
            "type": "string"
        },
        "password": {
            "title": "Password",
            "type": "string"
        },
        "roles": {
            "items": {
                "type": "string"
            },
            "type": "array"
        }
    },
    "required": [
        "name",
        "email"
    ],
    "title": "User",
    "type": "object"
}

{
    "definitions": {
        "tRef": {
            "$schema": "http://json-schema.org/draft-04/schema#",
            "description": "A definition reference.",
            "properties": {
                "refId": {
                    "description": "The identifier of a reference.",
                    "type": "string"
                }
            },
            "title": "tRef",
            "type": "object"
        }
    },
    "description": "The schema of a Sample",
    "properties": {
        "tArrayRef": {
            "items": {
                "$ref": "#/definitions/tRef"
            },
            "minItems": 1,
            "type": "array"
        },
        "tBoolean": {
            "default": true,
            "description": "The type boolean.",
            "type": "boolean"
        },
        "tDate": {
            "default": "2011-02-24T09:25:23.112+0000",
            "description": "The type date.",
            "format": "date-time",
            "type": "string"
        },
        "tInteger": {
            "description": "The type integer.",
            "type": "integer"
        },
        "tNumber": {
            "description": "The type number.",
            "minimum": 0,
            "type": "number"
        },
        "tString": {
            "description": "The type string.",
            "type": "string"
        }
    },
    "required": [
        "tInteger",
        "tArrayRef"
    ],
    "title": "Sample Schema",
    "type": "object"
}

{
    "type": "object",
    "title": "Profile schema",
    "$schema": "http://json-schema.org/draft-04/schema",
    "properties": {
        "id": {
            "type": [
                "integer",
                "string"
            ],
            "_db_settings": {
                "type": "id_field",
                "primary_key": true
            }
        },
        "created_at": {
            "type": [
                "string",
                "null"
            ],
            "format": "date-time",
            "_db_settings": {
                "type": "datetime",
                "default": "{{datetime.datetime.utcnow}}"
            }
        },
        "updated_at": {
            "type": [
                "string",
                "null"
            ],
            "format": "date-time",
            "_db_settings": {
                "type": "datetime",
                "onupdate": "{{datetime.datetime.utcnow}}"
            }
        },
        "address": {
            "type": [
                "string",
                "null"
            ],
            "_db_settings": {
                "type": "unicode_text"
            }
        },
        "user_id": {
            "type": [
                "string",
                "null"
            ],
            "_db_settings": {
                "type": "foreign_key",
                "ref_document": "User",
                "ref_column": "user.username",
                "ref_column_type": "string"
            }
        },
        "user": {
            "type": [
                "string",
                "null"
            ]
        }
    }
}

