                    }
                },
                "ipmi_port_ranges": {
                    "$id": "/properties/ipmi/properties/ipmi_port_ranges",
                    "type": "array",
                    "items": {
                        "$id": "/properties/ipmi/properties/ipmi_credentials/items",
