            "$id": "/properties/ironic",
            "type": "object",
            "required": [
                "auth_url",
                "username",
                "password"
            ],
            "properties": {
                "auth_url": {
                    "$id": "/properties/ironic/properties/auth_url",
                    "description": "The Ironic Auth URL",
